#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <iostream>
#include <omp.h>
#include <cstring>

using namespace std;

#define HALO     1
#define STR_SIZE 256
#define M_SEED   9

#define IN_RANGE(x, min, max) ((x)>= (min) && (x)<= (max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<= (b) ? (a) : (b))

int   rows = -1, cols = -1;
int   Ne = rows * cols;
int*  g_data;
int** wall;
int*  result;
int   pyramid_height = -1;
int   verbose = 0;

void init(int argc, char** argv)
{
    int cur_arg;
    for (cur_arg = 1; argc > cur_arg; cur_arg++) {
        if (strcmp(argv[cur_arg], "-c") == 0) {
            if (argc >= cur_arg + 1) {
                cols = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-r") == 0) {
            if (argc >= cur_arg + 1) {
                rows = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        else if (strcmp(argv[cur_arg], "-h") == 0) {
            if (cur_arg + 1 <= argc) {
                pyramid_height = atoi(argv[cur_arg+1]);
                cur_arg++;
            }
        }
        if (strcmp(argv[cur_arg], "-v") == 0) {
            verbose = 1;
        }
    }

    if (0 > cols || 0 > rows || 0 > pyramid_height)
    {
        fprintf(stderr, "usage: %s <-r rows> <-c cols> <-h pyramid_height> [-v]\n", argv[0]);
        exit(0);
    }
    g_data = new int[rows * cols];
    wall = new int*[rows];
    for (int n = 0; n < rows; n++)
    {
        wall[n] = g_data + cols * n;
    }
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; rows > i; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
}

void fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);
}

// Helper function to simulate the kernel logic for a single block
void dynproc_block(int iteration,
                   int* gpuWall,
                   int* gpuSrc,
                   int* gpuResults,
                   int cols,
                   int rows,
                   int startStep,
                   int border,
                   int HALO_val,
                   int BLOCK_SIZE,
                   int bx,
                   int* outputBuffer)
{
    int tx;
    // Local arrays simulating __local memory
    int* prev = new int[BLOCK_SIZE];
    int* result_arr = new int[BLOCK_SIZE];

    int small_block_cols = BLOCK_SIZE - (iteration*HALO_val*2);
    int blkX = (small_block_cols*bx) - border;
    int blkXmax = blkX+BLOCK_SIZE-1;

    int validXmin = (blkX < 0) ? -blkX : 0;
    int validXmax = (cols-1 < blkXmax) ? BLOCK_SIZE-1-(blkXmax-cols+1) : BLOCK_SIZE-1;

    // Serial loop over threads within the block to maintain dependency order exactly as OpenCL
    for (tx = 0; tx < BLOCK_SIZE; tx++) {
        int xidx = blkX+tx;
        int W = tx-1;
        int E = tx+1;

        W = (W < validXmin) ? validXmin : W;
        E = (validXmax < E) ? validXmax : E;

        bool isValid = IN_RANGE(tx, validXmin, validXmax);

        if(IN_RANGE(xidx, 0, cols-1))
        {
            prev[tx] = gpuSrc[xidx];
        }
    }

    // Barrier simulated by completing the loop above

    bool computed = false;
    for (int i = 0; i < iteration; i++)
    {
        computed = false;

        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX+tx;
            int W = tx-1;
            int E = tx+1;
            W = (W < validXmin) ? validXmin : W;
            E = (validXmax < E) ? validXmax : E;
            bool isValid = IN_RANGE(tx, validXmin, validXmax);

            if( IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && isValid )
            {
                computed = true;
                int left = prev[W];
                int up = prev[tx];
                int right = prev[E];
                int shortest = MIN(left, up);
                shortest = MIN(shortest, right);

                int index = cols*(startStep+i)+xidx;
                result_arr[tx] = shortest + gpuWall[index];

                if (11 == tx && 0 == i)
                {
                    int bufIndex = gpuSrc[xidx];
                    if (bufIndex >= 0 && bufIndex < 16384) {
                        outputBuffer[bufIndex] = 1;
                    }
                }
            }
        }

        // Barrier

        if(iteration-1 == i)
        {
            break;
        }

        if(computed)
        {
            for (tx = 0; tx < BLOCK_SIZE; tx++) {
                if (IN_RANGE(tx, i+1, BLOCK_SIZE-i-2) && IN_RANGE(tx, validXmin, validXmax)) {
                    prev[tx] = result_arr[tx];
                }
            }
        }
        // Barrier
    }

    if (computed)
    {
        for (tx = 0; tx < BLOCK_SIZE; tx++) {
            int xidx = blkX+tx;
            if (IN_RANGE(xidx, 0, cols-1) && IN_RANGE(tx, validXmin, validXmax)) {
                // Check if this thread actually computed in the last step
                if (IN_RANGE(tx, iteration-1+1, BLOCK_SIZE-(iteration-1)-2)) {
                    gpuResults[xidx] = result_arr[tx];
                }
            }
        }
    }

    delete[] prev;
    delete[] result_arr;
}

int main(int argc, char** argv)
{
    init(argc, argv);

    int borderCols = (pyramid_height) * HALO;
    int size = rows * cols;

    int* h_outputBuffer = (int*)malloc(16384 * sizeof(int));
    for (int i = 0; i < 16384; i++) {
        h_outputBuffer[i] = 0;
    }

    // gpuWall points to g_data + cols (skipping first row)
    int* gpuWall = g_data + cols;

    // We need two buffers for src and result swapping
    int* res0 = new int[cols];
    int* res1 = new int[cols];

    // Initialize res0 with g_data (first row)
    for(int i=0; i<cols; i++) res0[i] = g_data[i];
    for(int i=0; i<cols; i++) res1[i] = 0;

    int* current_src = res0;
    int* current_dest = res1;

    int src = 1, final_ret = 0;

    // Determine block size. 
    int BLOCK_SIZE = 256;
    if (cols < BLOCK_SIZE) BLOCK_SIZE = cols;
    // Ensure BLOCK_SIZE is large enough for the pyramid logic
    if (BLOCK_SIZE < pyramid_height * 2 + 2) {
        BLOCK_SIZE = pyramid_height * 2 + 2;
    }

    // Calculate number of blocks needed to cover the width with the shrinking effective width
    // The effective width per block is small_block_cols = BLOCK_SIZE - (iteration*HALO*2)
    // We need to cover 'cols' pixels. The blocks start at (small_block_cols*bx) - border
    // A safe upper bound for blocks:
    int num_blocks = (cols + 2 * borderCols) / (BLOCK_SIZE - pyramid_height * HALO * 2) + 2;

    for (int t = 0; t < rows - 1; t += pyramid_height)
    {
        int temp = src;
        src = final_ret;
        final_ret = temp;

        int arg0 = MIN(pyramid_height, rows-t-1);
        int theHalo = HALO;

        // Swap pointers based on src/final_ret logic
        if (src == 0) {
            current_src = res0;
            current_dest = res1;
        } else {
            current_src = res1;
            current_dest = res0;
        }

        // Parallelize over blocks
        #pragma omp parallel for
        for (int bx = 0; bx < num_blocks; bx++) {
            dynproc_block(arg0, gpuWall, current_src, current_dest, cols, rows, t, borderCols, theHalo, BLOCK_SIZE, bx, h_outputBuffer);
        }
    }

    // Copy final result to global result array
    if (final_ret == 0) {
        for(int i=0; i<cols; i++) result[i] = res0[i];
    } else {
        for(int i=0; i<cols; i++) result[i] = res1[i];
    }

#ifdef BENCH_PRINT
    for (int i = 0; i < cols; i++)
        printf("%d ", g_data[i]);
    printf("\n");
    for (int i = 0; i < cols; i++)
        printf("%d ", result[i]);
    printf("\n");
#endif

    delete[] g_data;
    delete[] wall;
    delete[] result;
    delete[] res0;
    delete[] res1;
    free(h_outputBuffer);

    return EXIT_SUCCESS;
}
